INSERT INTO `activities` (`id`, `activity_code`, `name`, `scenic_id`, `merchant_id`, `category`, `description`, `content`, `cover_image`, `images`, `start_time`, `end_time`, `location`, `participant_limit`, `current_participants`, `registration_start`, `registration_end`, `price`, `contact_person`, `contact_phone`, `tags`, `status`, `is_promoted`, `promoted_at`, `news_id`, `views`, `created_at`, `updated_at`, `deleted_at`) VALUES (1,'AC001','梅花节',1,12,'节庆活动','春季赏梅活动，赏花品茗','<p>梅花山春季梅花节盛大开幕，数万株梅花竞相绽放，欢迎游客前来赏花品茗。</p><p>活动期间有茶艺表演、摄影大赛、美食品鉴等精彩活动。</p>','https://smarttourism717.oss-cn-beijing.aliyuncs.com/scenic/meihua.jpg',NULL,'2024-02-15','2024-03-15','梅花山主景区',25800,0,NULL,NULL,0.00,'张经理','17590238191','[\"赏花\", \"文化体验\", \"摄影\"]','completed',0,NULL,NULL,0,'2025-10-19 07:02:53','2025-10-19 07:28:11','2025-10-19 07:28:11'),(2,'AC002','高山徒步挑战赛',1,12,'体育赛事','登山徒步竞技活动','<p>挑战自我，征服梅花山！全程15公里，海拔上升800米。</p><p>设有专业组和业余组，完赛者颁发证书和纪念品。</p>','https://smarttourism717.oss-cn-beijing.aliyuncs.com/scenic/hiking.jpg',NULL,'2023-07-15','2023-07-16','梅花山登山道',3200,0,NULL,NULL,50.00,'李教练','17590238192','[\"运动健身\", \"挑战赛\"]','completed',0,NULL,NULL,0,'2025-10-19 07:02:53','2025-10-19 07:28:13','2025-10-19 07:28:13'),(3,'AC004','梅花山摄影大赛',1,12,'文化活动','风光摄影比赛','<p>用镜头记录梅花山的美丽瞬间，优秀作品将获得丰厚奖金。</p><p>设一等奖1名（奖金5000元）、二等奖3名、三等奖10名。</p>','https://smarttourism717.oss-cn-beijing.aliyuncs.com/scenic/photography.jpg',NULL,'2023-09-01','2023-10-31','梅花山全景区',5600,0,NULL,NULL,0.00,'王老师','17590238193','[\"摄影\", \"艺术\", \"比赛\"]','completed',0,NULL,NULL,0,'2025-10-19 07:02:53','2025-10-19 07:28:15','2025-10-19 07:28:15'),(7,'ACT120251019154747','测试活动',1,12,NULL,'测试666',NULL,'https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760859848411.jpg',NULL,'2025-10-01','2025-10-29',NULL,0,0,NULL,NULL,0.00,NULL,NULL,'[\"节日活动\"]','active',1,'2025-10-19 16:18:22',NULL,0,'2025-10-19 07:47:47','2025-10-19 08:18:22',NULL),(8,'ACT120251019161237','测试活动',1,12,NULL,'测试',NULL,'https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760861549950.jpg',NULL,'2025-10-01','2025-10-28',NULL,0,0,NULL,NULL,0.00,NULL,NULL,'[\"季节限定\", \"团建活动\"]','active',1,'2025-10-19 16:18:22',NULL,0,'2025-10-19 08:12:38','2025-10-20 12:19:12','2025-10-20 12:19:12'),(9,'ACT120251019161650','测试',1,12,NULL,'测试',NULL,'https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760861801626.jpg',NULL,'2025-10-01','2025-10-31',NULL,0,0,NULL,NULL,0.00,NULL,NULL,'[\"季节限定\", \"亲子活动\"]','active',0,NULL,NULL,0,'2025-10-19 08:16:50','2025-10-19 08:19:11','2025-10-19 08:19:11'),(10,'ACT120251019161941','测试活动',1,12,NULL,'测试111',NULL,'https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760861975921.jpg',NULL,'2025-10-01','2025-10-31',NULL,0,0,NULL,NULL,0.00,NULL,NULL,'[\"节日活动\", \"文化表演\", \"体育赛事\"]','active',1,'2025-10-19 16:21:04',NULL,0,'2025-10-19 08:19:42','2025-10-20 12:19:11','2025-10-20 12:19:11'),(11,'ACT120251019162344','测试活动222',1,12,NULL,'666',NULL,'https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760862216905.jpg',NULL,'2025-10-01','2025-10-31',NULL,0,0,NULL,NULL,0.00,NULL,NULL,'[\"体育赛事\", \"特色体验\", \"季节限定\", \"亲子活动\"]','active',1,'2025-10-19 16:26:34',13,0,'2025-10-19 08:23:45','2025-10-20 12:19:09','2025-10-20 12:19:09'),(12,'ACT120251020144951','测试',1,12,NULL,'测试',NULL,'https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760942984010.jpg',NULL,'2025-10-01','2025-10-31',NULL,0,0,NULL,NULL,0.00,NULL,NULL,'[\"节日活动\", \"文化表演\"]','active',0,NULL,NULL,0,'2025-10-20 06:49:52','2025-10-20 07:13:58','2025-10-20 07:13:58'),(13,'ACT120251020145246','测试',1,12,NULL,'测试',NULL,'https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760943158239.jpg',NULL,'2025-10-01','2025-10-31',NULL,0,0,NULL,NULL,0.00,NULL,NULL,'[\"节日活动\", \"文化表演\", \"特色体验\"]','active',0,NULL,NULL,0,'2025-10-20 06:52:47','2025-10-20 07:13:56','2025-10-20 07:13:56'),(14,'ACT120251020201948','冬季主题活动（2025 年 12 月 - 2026 年 3 月）',1,12,NULL,'梅花山国际滑雪季（12 月 16 日 - 3 月 31 日）\n雪道升级：新增 100 米单板公园，初、中、高级道配备专业教练团队，提供 1 对 1 教学。\n夜间狂欢：每周五、六及春节期间开放 “梭坡坡奇妙夜”，雪场灯光秀 + 雪地蹦迪，夜场票 128 元（含索道）。\n地域优惠：广东省、大连市及周边五城居民凭身份证享门票 8 折，教师、医护人员凭证件同享优惠。',NULL,'https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760962781355.jpg',NULL,'2025-10-01','2025-10-31',NULL,0,0,NULL,NULL,0.00,NULL,NULL,'[\"节日活动\", \"文化表演\"]','active',1,'2025-10-20 20:20:14',14,0,'2025-10-20 12:19:49','2025-10-20 12:20:38',NULL);
