INSERT INTO `ai_conversations` (`id`, `conversation_uuid`, `user_id`, `scenic_id`, `type`, `title`, `last_message`, `message_count`, `created_at`, `updated_at`, `deleted`) VALUES (1,'93f9fefb-4c43-4036-8c75-b7cd9ddcbfa2',NULL,0,'chat','你好呀','你好呀！欢迎来到“智教黔行·时空旅 绘梦蓝图”六盘水旅游智能客服系统～😊  \n我是您的专属旅游助手，很高兴为您服务！\n\n当前时间是：**2026年2月7日（星期六）下午15:31**，正值农历腊月廿...',2,'2026-02-07 15:31:21','2026-02-07 15:31:29',0),(2,'405ddb35-4a45-4009-94f9-19139f3f434b',4,1,'chat','作为一个专业的旅游数据分析师，请基于以下客流预测数据，为游客...','1. **最佳游览时间建议**  \n   推荐选择2月10日至2月13日之间游览，客流相对平稳，且低于平均值，适合避开高峰。若希望体验更舒适环境，可优先选择2月11日或12日。\n\n2. **需要注意的...',2,'2026-02-07 18:14:31','2026-02-07 18:14:36',0),(3,'24853c73-e522-4836-9ac4-90756d90a9e1',4,1,'chat','作为一个专业的旅游数据分析师，请基于以下客流预测数据，为游客...','1. **最佳游览时间建议**：  \n建议选择2月10日或2月11日前往梅花山风景区，这两天客流相对较低，拥挤度适中，适合深度游览与休闲体验。\n\n2. **需要注意的事项**：  \n由于天气信息未知，...',2,'2026-02-07 18:22:07','2026-02-07 18:22:10',0),(4,'3ed41dac-302f-4ae9-af54-8cb6d5e049ae',NULL,NULL,'chat','mp_1771325506490_p2kbdl','您好，您提到的似乎是某种编号或代码，但未说明具体需求。请问您需要了解六盘水的哪些信息？例如景区介绍、旅游路线、特色活动等，我将为您详细解答。',2,'2026-02-17 18:51:52','2026-02-17 18:51:53',0),(5,'4e398552-16ba-458b-8e06-b1bc703ba999',NULL,NULL,'chat','mp_1771325974287_qq6dvh','您好，您提到的号码似乎不是有效的联系方式。如果您有关于六盘水旅游的问题或需要帮助，请随时告诉我，我将竭诚为您服务！',2,'2026-02-17 18:59:49','2026-02-17 18:59:50',0),(6,'3c481192-a5e1-440e-8064-5936f7524e16',NULL,NULL,'chat','mp_1771326218875_0c770e','您好，我是六盘水旅游智能客服。您需要了解哪些景区信息呢？六盘水有梅花山、乌蒙大草原、明湖湿地、玉舍森林公园和水城古镇等景点，每个都有独特的自然风光和文化特色。请问您对哪个景区感兴趣？',2,'2026-02-17 19:03:41','2026-02-17 19:03:42',0),(7,'77755230-c577-4257-b2d7-e6647a913bd0',NULL,NULL,'chat','mp_1771326317875_3qvzrr','您好，您似乎输入了无效内容。我是六盘水旅游智能客服，很高兴为您服务。六盘水被誉为“中国凉都”，拥有梅花山、乌蒙大草原、明湖湿地、玉舍森林公园和水城古镇等特色景区。请问您想了解哪些信息呢？',2,'2026-02-17 19:05:19','2026-02-17 19:05:20',0),(8,'9a3c2fc7-f15d-4e59-bbb6-35d3c277a4d1',NULL,NULL,'chat','六盘水有哪些必去景点？','六盘水必去景点包括：梅花山（以梅花观赏和生态休闲为主）、乌蒙大草原（高原草原与贵州屋脊景观）、明湖湿地（城市生态与休闲观光）、玉舍森林公园（原始森林与滑雪体验）以及水城古镇（历史民俗与非遗文化）。这些...',2,'2026-02-17 22:00:50','2026-02-17 22:00:52',0),(9,'1089400e-020a-48f8-9b5f-b8979a32520b',NULL,NULL,'chat','六盘水有哪些必去景点？','六盘水必去景点包括：梅花山（以梅花观赏和生态休闲为主）、乌蒙大草原（高原草原与贵州屋脊景观）、明湖湿地（城市生态与休闲观光）、玉舍森林公园（原始森林与滑雪体验）以及水城古镇（历史民俗与非遗文化）。这些...',2,'2026-02-17 22:07:12','2026-02-17 22:07:12',0),(10,'bbf5f7d2-acd3-407d-8515-9c47d5c523c7',NULL,NULL,'chat','六盘水有哪些必去景点？','六盘水必去景点包括：梅花山（以梅花观赏和生态休闲为主）、乌蒙大草原（高原草原与贵州屋脊景观）、明湖湿地（城市生态与休闲观光）、玉舍森林公园（原始森林与滑雪体验）以及水城古镇（历史民俗与非遗文化）。这些...',2,'2026-02-17 22:09:06','2026-02-17 22:09:06',0),(11,'17556ecb-0fab-4d27-afec-b754077c8457',NULL,NULL,'chat','六盘水有哪些必去景点？','六盘水必去景点包括：梅花山（以梅花观赏和生态休闲为主）、乌蒙大草原（高原草原与贵州屋脊景观）、明湖湿地（城市生态与休闲观光）、玉舍森林公园（原始森林与滑雪体验）以及水城古镇（历史民俗与非遗文化）。这些...',2,'2026-02-17 22:16:45','2026-02-17 22:16:46',0),(12,'9fea73e2-8c03-4664-8a5d-1bfd05dbb72c',NULL,NULL,'chat','六盘水有哪些必去景点？','六盘水必去景点包括：梅花山（以梅花观赏和生态休闲为主）、乌蒙大草原（高原草原与贵州屋脊景观）、明湖湿地（城市生态与休闲观光）、玉舍森林公园（原始森林与滑雪体验）以及水城古镇（历史民俗与非遗文化）。这些...',2,'2026-02-17 22:22:16','2026-02-17 22:22:16',0),(13,'416e11b0-a03e-4438-bb46-3acdf81bb219',NULL,NULL,'chat','六盘水有哪些必去景点？','六盘水必去景点包括：梅花山（以梅花观赏和生态休闲为主）、乌蒙大草原（高原草原与贵州屋脊景观）、明湖湿地（城市生态与休闲观光）、玉舍森林公园（原始森林与滑雪体验）以及水城古镇（历史民俗与非遗文化）。这些...',2,'2026-02-17 22:29:20','2026-02-17 22:29:20',0);
