INSERT INTO `ai_knowledge` (`id`, `title`, `content`, `category`, `scenic_id`, `source`, `keywords`, `enabled`, `created_at`, `updated_at`, `deleted`) VALUES (1,'梅花山风景区介绍','梅花山风景区位于贵州省六盘水市钟山区，是六盘水的城市名片。景区以梅花观赏、生态休闲为特色，拥有万亩梅园、滑雪场、温泉等多种旅游资源。梅花山海拔2680米，是贵州海拔最高的景区之一。每年冬季的梅花盛开期间，吸引大量游客前来赏梅。门票价格：60元/人。','scenic',NULL,'六盘水市文旅局','梅花山,梅花,滑雪,温泉,钟山区',1,'2026-02-07 15:04:29','2026-02-07 15:04:29',0),(2,'乌蒙大草原介绍','乌蒙大草原位于贵州省六盘水市盘州市，被誉为\"贵州屋脊\"。草原平均海拔2857米，是贵州海拔最高的草原。这里有广袤的高山草原、壮观的风电场、独特的高原气候。适合户外徒步、骑马、露营等活动。门票价格：65元/人。','scenic',NULL,'六盘水市文旅局','乌蒙,草原,盘州,高原,风电',1,'2026-02-07 15:04:29','2026-02-07 15:04:29',0),(3,'玉舍国家森林公园介绍','玉舍国家森林公园位于六盘水市水城区，拥有原始森林、珍稀动植物等自然资源。公园内有滑雪场、森林步道、观景台等设施，四季皆宜旅游。冬季可滑雪，夏季可避暑，是六盘水重要的生态旅游景区。门票价格：40元/人。','scenic',NULL,'六盘水市文旅局','玉舍,森林,滑雪,水城区,生态',1,'2026-02-07 15:04:29','2026-02-07 15:04:29',0),(4,'明湖国家湿地公园介绍','明湖国家湿地公园位于六盘水市钟山区，是城市中的生态湿地。公园免费开放，适合市民休闲散步、观鸟、拍照。湿地生态系统完善，有丰富的水生植物和鸟类资源。','scenic',NULL,'六盘水市文旅局','明湖,湿地,免费,钟山区,生态',1,'2026-02-07 15:04:29','2026-02-07 15:04:29',0),(5,'水城古镇介绍','水城古镇位于六盘水市水城区，是一个具有悠久历史的古镇。古镇展现了当地彝族、苗族等少数民族的民俗风情，有特色建筑、传统手工艺、地方美食等。古镇免费开放。','scenic',NULL,'六盘水市文旅局','水城古镇,历史,彝族,苗族,民俗',1,'2026-02-07 15:04:29','2026-02-07 15:04:29',0),(6,'六盘水气候特色','六盘水素有\"中国凉都\"之称，夏季平均气温仅19.7℃，是中国避暑旅游的理想目的地。六盘水属亚热带季风湿润气候，四季分明，冬无严寒，夏无酷暑。最佳旅游季节为5-10月。','culture',NULL,'六盘水市政府','凉都,气候,避暑,温度,季节',1,'2026-02-07 15:04:29','2026-02-07 15:04:29',0),(7,'六盘水特色美食','六盘水美食以辣为主，代表性美食包括：水城烙锅（最具特色）、羊肉粉、烤豆腐、荞面、酸汤鱼等。水城烙锅是六盘水的名片美食，用特制的凹形砂锅烙制各种食材，味道鲜美独特。','food',NULL,'六盘水市文旅局','烙锅,羊肉粉,美食,特色小吃',1,'2026-02-07 15:04:29','2026-02-07 15:04:29',0),(8,'六盘水交通指南','六盘水交通便利：1. 航空：月照机场有直飞北京、上海、广州等城市航线；2. 铁路：六盘水站是西南地区重要铁路枢纽，有高铁和普速列车；3. 公路：沪昆高速、杭瑞高速经过六盘水；4. 市内交通：公交系统完善，出租车起步价5元。','transport',NULL,'六盘水市交通局','交通,机场,高铁,公交,自驾',1,'2026-02-07 15:04:29','2026-02-07 15:04:29',0);
/*!40000 ALTER TABLE `ai_knowledge` ENABLE KEYS */;
UNLOCK TABLES;

