DROP TABLE IF EXISTS `ai_study_routes`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ai_study_routes` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '路线ID',
