INSERT INTO `facilities` (`id`, `facility_code`, `name`, `scenic_id`, `merchant_id`, `category`, `description`, `location`, `latitude`, `longitude`, `capacity`, `opening_hours`, `contact_phone`, `thumbnail`, `images`, `features`, `price_info`, `status`, `is_free`, `rating`, `review_count`, `created_at`, `updated_at`, `deleted_at`) VALUES (1,'FAC001','梅花山游客中心',1,12,'服务中心','提供咨询、导游、售票等服务','景区入口',NULL,NULL,200,'08:00-18:00','17590238191','/images/default-facility.jpg',NULL,'[\"咨询服务\", \"导游服务\", \"行李寄存\", \"充电服务\", \"母婴室\"]','免费','normal',1,0.00,0,'2025-10-19 07:02:53','2025-10-19 07:37:53','2025-10-19 07:28:17'),(2,'FAC002','梅花山生态停车场',1,12,'停车场','大型生态停车场，可停放500辆车','景区外围',NULL,NULL,500,'00:00-24:00','17590238191','/images/default-facility.jpg',NULL,'[\"24小时监控\", \"充电桩\", \"遮阳棚\"]','小车10元/次，大车20元/次','normal',0,0.00,0,'2025-10-19 07:02:53','2025-10-19 07:37:53','2025-10-19 07:28:19'),(3,'FAC003','梅香餐厅',1,12,'餐厅','特色农家菜餐厅，提供贵州本地美食','景区中部',NULL,NULL,150,'11:00-14:00, 17:00-20:00','17590238194','/images/default-facility.jpg',NULL,'[\"贵州菜\", \"农家菜\", \"素食\", \"包厢\"]','人均消费60-80元','normal',0,0.00,0,'2025-10-19 07:02:53','2025-10-19 07:37:53','2025-10-19 07:28:21'),(4,'FAC004','山顶观景台',1,12,'观景点','360度全景观景台，可俯瞰六盘水全景','梅花山主峰',NULL,NULL,100,'08:00-18:00','17590238191','/images/default-facility.jpg',NULL,'[\"观景\", \"拍照\", \"休息区\", \"望远镜\"]','免费','normal',1,0.00,0,'2025-10-19 07:02:53','2025-10-19 07:37:53','2025-10-19 07:28:22'),(5,'FAC005','医疗救助站',1,12,'医疗点','提供紧急医疗救助和常用药品','游客中心内',NULL,NULL,20,'08:00-18:00','17590238195','/images/default-facility.jpg',NULL,'[\"紧急救助\", \"常用药品\", \"血压测量\", \"应急设备\"]','免费','normal',1,0.00,0,'2025-10-19 07:02:53','2025-10-19 07:37:53','2025-10-19 07:28:23'),(11,'FAC120251019155114','测试',1,12,NULL,'测试',NULL,NULL,NULL,100,'08:00-18:00',NULL,'/images/default-facility.jpg',NULL,NULL,NULL,'active',1,0.00,0,'2025-10-19 07:51:15','2025-10-19 07:56:47','2025-10-19 07:56:47'),(12,'FAC120251019155709','测试',1,12,NULL,'测试',NULL,NULL,NULL,100,'08:00-18:00',NULL,'