--
-- Dumping data for table `news`
--

LOCK TABLES `news` WRITE;
/*!40000 ALTER TABLE `news` DISABLE KEYS */;
INSERT INTO `news` (`id`, `title`, `summary`, `content`, `category`, `covers`, `scenic_id`, `author_id`, `views`, `status`, `publish_time`, `created_at`, `updated_at`, `activity_id`, `source`) VALUES (8,'《六盘水的 “城市绿宝石”！明湖湿地：免费逛，在城市里邂逅自然疗愈～》','','明湖国家湿地公园，是六盘水市中心的 “生态秘境”。澄澈湖水、葱郁植被与现代桥梁相映成趣，漫步其中，既能感受湿地生态的清幽静谧，又能在 “城市繁华” 与 “自然野趣” 间自由切换。饭后散步、周末野餐，或是单纯逃离喧嚣 “吸氧”，这里都是疗愈身心的绝佳之选～','景点推荐',NULL,5,18,0,'published','2025-10-19 05:28:54','2025-10-19 05:28:54','2025-10-19 05:28:54',NULL,'manual'),(9,'《免费沉浸式体验！水城古镇：百年街巷里，藏着六盘水最浓的烟火与民俗～》','','免费开放的水城古镇，是六盘水历史文化的 “活态博物馆”。青石板路、复古建筑镌刻着岁月痕迹，街头民俗表演热闹鲜活，特色小吃摊（如烙锅、羊肉粉）香气直钻鼻腔，手工艺品店摆满精巧的非遗物件…… 走进这里，仿佛穿越时光，一站式感受六盘水的烟火气与民俗魅力～','旅游攻略',NULL,4,19,0,'published','2025-10-19 05:29:29','2025-10-19 05:29:29','2025-10-19 05:29:29',NULL,'manual'),(10,'《闯进 “贵州屋脊” 童话！乌蒙大草原：草原、风电、牧场同框，随手拍都是 “天花板级” 大片～》','','被誉为 “贵州屋脊” 的乌蒙大草原，把 “高山草原的辽阔 + 风电场的科技感 + 牧场的悠然” 完美融合。站在草原上，巨型风电叶片缓缓转动，成群牛羊悠然踱步，无边草甸在眼前铺展（秋冬更显金黄苍茫）。来这里露营、追日出日落，仿佛一头扎进自由又壮美的童话世界～','景点推荐',NULL,3,16,0,'published','2025-10-19 05:30:25','2025-10-19 05:30:25','2025-10-19 05:30:25',NULL,'manual'),(11,'《全年不重样的快乐！玉舍国家森林公园：原始森林、华南最大滑雪场，承包你四季的期待～》','','藏着 “原始森林 + 华南最大滑雪场” 的玉舍国家森林公园，堪称 “四季宝藏地”！春可探森林野花、夏能避暑吸氧、秋赏层林尽染，冬季更能一头扎进林海雪原，在华南最大滑雪场体验 “雪上飞驰” 的刺激。自然爱好者、滑雪发烧友…… 不同季节来，都能收获专属快乐～','旅游攻略',NULL,2,17,1,'published','2025-10-19 05:31:00','2025-10-19 05:31:00','2025-10-19 05:31:00',NULL,'manual'),(12,'《初冬赴一场 “梅” 好之约！梅花山风景区：山水作幕，寒梅待放，诗意值拉满～》','','作为国家 4A 级景区，梅花山风景区以 “山水秀丽 + 西南赏梅胜地” 著称。当下时节，山间梅林正酝酿着 “傲骨绽放” 的浪漫，山水云雾与朦胧梅影交织，宛如天然水墨画卷。无论是提前来赴 “寒梅之约”，还是漫游山间吸氧洗肺，都能解锁六盘水初冬独有的诗意与松弛～','景点推荐',NULL,1,12,5,'published','2025-10-19 05:31:38','2025-10-19 05:31:38','2025-10-19 05:31:38',NULL,'manual'),(14,'冬季主题活动（2025 年 12 月 - 2026 年 3 月）','梅花山国际滑雪季（12 月 16 日 - 3 月 31 日）\n雪道升级：新增 100 米单板公园，初、中、高级道配备专业教练团队，提供 1 对 1 教学。\n夜间狂欢：每周五、六及春节期间开放 “梭坡坡奇妙夜”，雪场灯光秀 + 雪地蹦迪，夜场票 128 元（含索道）。\n地域优惠：广东省、大连市及周边五城居民凭身份证享门票 8 折，教师、医护人员凭证件同享优惠。','梅花山国际滑雪季（12 月 16 日 - 3 月 31 日）\n雪道升级：新增 100 米单板公园，初、中、高级道配备专业教练团队，提供 1 对 1 教学。\n夜间狂欢：每周五、六及春节期间开放 “梭坡坡奇妙夜”，雪场灯光秀 + 雪地蹦迪，夜场票 128 元（含索道）。\n地域优惠：广东省、大连市及周边五城居民凭身份证享门票 8 折，教师、医护人员凭证件同享优惠。','event','[\"https://smarttourism717.oss-cn-beijing.aliyuncs.com/files/12/202510/1760962781355.jpg\"]',1,12,4,'published','2025-10-20 12:20:14','2025-10-20 12:20:14','2025-10-20 12:20:14',14,'activity');
/*!40000 ALTER TABLE `news` ENABLE KEYS */;
UNLOCK TABLES;

