--
-- Table structure for table `scenic_spots`
--

DROP TABLE IF EXISTS `scenic_spots`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `scenic_spots` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '景区ID',
  `parent_id` bigint DEFAULT NULL COMMENT '父景区ID，NULL表示主景区',
  `sort_order` int DEFAULT '0' COMMENT '排序序号',
  `spot_code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '景区编码',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '景区名称',
  `city` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT '六盘水' COMMENT '所属城市',
  `category` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '景区分类',
  `level` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '景区等级',
  `address` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '详细地址',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '简短描述',
  `full_description` text COLLATE utf8mb4_unicode_ci COMMENT '详细描述',
  `image_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '主图URL',
  `map_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '地图图片URL',
  `latitude` decimal(10,7) DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(10,7) DEFAULT NULL COMMENT '经度',
  `opening_hours` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '开放时间',
  `price` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '门票价格',
  `suggested_time` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '建议游玩时长',
  `max_capacity` int NOT NULL DEFAULT '10000' COMMENT '最大承载量',
  `rating` decimal(2,1) NOT NULL DEFAULT '0.0' COMMENT '评分',
  `favorites_count` int DEFAULT '0' COMMENT '收藏数',
  `review_count` int NOT NULL DEFAULT '0' COMMENT '评价数量',
  `visit_count` int NOT NULL DEFAULT '0' COMMENT '访问次数',
  `tags` json DEFAULT NULL COMMENT '标签数组',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态：ACTIVE/MAINTENANCE/INACTIVE',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '软删除时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_spot_code` (`spot_code`),
  KEY `idx_city` (`city`),
  KEY `idx_category` (`category`),
  KEY `idx_status` (`status`),
  KEY `idx_rating` (`rating`),
  KEY `idx_location` (`latitude`,`longitude`),
  KEY `idx_deleted_at` (`deleted_at`),
  KEY `idx_favorites_count` (`favorites_count` DESC),
  KEY `idx_parent_id` (`parent_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='景区表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `scenic_spots`
--

LOCK TABLES `scenic_spots` WRITE;
/*!40000 ALTER TABLE `scenic_spots` DISABLE KEYS */;
INSERT INTO `scenic_spots` (`id`, `parent_id`, `sort_order`, `spot_code`, `name`, `city`, `category`, `level`, `address`, `description`, `full_description`, `image_url`, `map_image`, `latitude`, `longitude`, `opening_hours`, `price`, `suggested_time`, `max_capacity`, `rating`, `favorites_count`, `review_count`, `visit_count`, `tags`, `status`, `created_at`, `updated_at`, `deleted_at`) VALUES (1,NULL,0,'MHS001','梅花山风景区','六盘水','自然景观','5A','贵州省六盘水市钟山区梅花山国际度假区','','梅花山风景区位于贵州省六盘水市钟山区，是国家4A级旅游景区。景区海拔2200米，夏季平均气温19℃，有\"天然大空调\"之美誉。这里山峦叠嶂，林海茫茫，梅花盛开时节，漫山遍野的梅花如诗如画。\r\n\r\n     景区主要景点包括：\r\n     - 梅花谷：万株梅花竞相开放，形成壮观的梅海景观\r\n     - 观景台：可俯瞰整个六盘水市区，视野开阔\r\n     - 梅花山索道：全长2.3公里，可欣赏沿途美景\r\n     - 生态步道：穿越原始森林，呼吸新鲜空气\r\n\r\n     最佳游览时间：\r\n     - 春季（3-4月）：梅花盛开，满山芬芳\r\n     - 夏季（6-8月）：避暑胜地，清凉宜人\r\n     - 冬季（12-2月）：雪景迷人，银装素裹',NULL,NULL,26.5945000,104.8336000,'08:30-18:00','60元/人','3-4小时',5000,4.7,2,3256,0,'[\"4A级景区\", \"赏梅胜地\", \"避暑胜地\", \"摄影天堂\"]','ACTIVE','2025-10-16 10:43:00','2026-02-24 08:46:20',NULL),(2,NULL,0,'YSH002','玉舍国家森林公园','六盘水','自然景观','4A','贵州省六盘水市水城区玉舍镇','拥有原始森林和华南最大的滑雪场，四季皆宜。','玉舍国家森林公园位于贵州省六盘水市水城区玉舍镇，是国家4A级旅游景区，也是贵州省第一个国家级森林公园。景区总面积50.3平方公里，森林覆盖率达90.73%。\r\n\r\n     主要特色：\r\n     - 玉舍雪山滑雪场：华南地区最大的高山滑雪场，雪期长达3个月\r\n     - 原始森林：保存完好的亚热带常绿阔叶林，树龄超过百年的古树随处可见\r\n     - 林中小屋：特色森林木屋住宿，体验森林生活\r\n     - 森林氧吧：负氧离子含量极高，是天然的养生保健地\r\n\r\n     四季景观：\r\n     - 春季：杜鹃花海，漫山红遍\r\n     - 夏季：避暑胜地，平均气温19℃\r\n     - 秋季：层林尽染，五彩斑斓\r\n     - 冬季：滑雪天堂，冰雪世界',NULL,NULL,26.6203000,104.7608000,'08:00-18:00','60元/人（滑雪另收费）','4-5小时',6000,4.8,2,4521,0,'[\"4A级景区\", \"滑雪场\", \"森林氧吧\", \"避暑胜地\"]','ACTIVE','2025-10-16 10:43:00','2025-10-19 05:51:58',NULL),(3,NULL,0,'WMC003','乌蒙大草原','六盘水','自然景观','4A','贵州省六盘水市盘州市乌蒙镇','贵州屋脊，高山草原，风电场与牧场的完美结合。','乌蒙大草原位于贵州省六盘水市盘州市乌蒙镇，是国家4A级旅游景区。景区平均海拔2500米，是贵州省海拔最高的草原，有\"贵州屋脊\"之称。\r\n\r\n     景区特色：\r\n     - 高山草原：10万亩高山草原，一望无际，牛羊成群\r\n     - 风电场：巨型风力发电机群，与草原构成独特景观\r\n     - 长海子：高山湖泊，碧波荡漾，倒映蓝天白云\r\n     - 佛顶山：海拔2900米，可观日出云海\r\n\r\n     体验项目：\r\n     - 骑马：在草原上策马奔腾\r\n     - 露营：搭帐篷看星空，体验草原夜晚\r\n     - 滑草：夏季滑草体验\r\n     - 观光小火车：环游草原\r\n\r\n     最佳游览时间：\r\n     - 夏季（6-9月）：草原最美时节，绿草如茵\r\n     - 秋季（10-11月）：草原金黄，别有韵味',NULL,NULL,26.0708000,104.4532000,'08:00-18:00','30元/人','5-6小时',8000,4.6,1,5896,0,'[\"4A级景区\", \"高山草原\", \"贵州屋脊\", \"风电场\"]','ACTIVE','2025-10-16 10:43:00','2025-10-16 10:43:00',NULL),(4,NULL,0,'SCGZ004','水城古镇','六盘水','人文景观','4A','贵州省六盘水市水城区古镇路','历史文化古镇，展现地方民俗风情，免费开放。','水城古镇位于贵州省六盘水市水城区，是一座具有600多年历史的文化古镇。古镇保留了明清时期的建筑风格，青石板路、木质吊脚楼、古老的城墙，诉说着历史的沧桑。\r\n\r\n     古镇特色：\r\n     - 古建筑群：明清时期的民居、祠堂、庙宇保存完好\r\n     - 民族文化：彝族、苗族、布依族等多民族文化交融\r\n     - 特色美食：水城羊肉粉、烙锅、酸汤鱼等地道美食\r\n     - 手工艺品：蜡染、刺绣、银饰等民族手工艺品\r\n\r\n     主要景点：\r\n     - 古城墙：明代城墙遗址\r\n     - 文昌阁：古代文人祭拜文昌帝君的场所\r\n     - 民俗博物馆：展示水城地区的历史文化\r\n     - 古戏台：定期上演地方戏曲\r\n\r\n     游览提示：\r\n     - 免费开放，全天候开放\r\n     - 适合慢游，品味古镇韵味\r\n     - 傍晚时分，古镇灯光亮起，别有风情',NULL,NULL,26.5402000,104.9537000,'全天开放','免费','2-3小时',3000,4.5,0,2134,0,'[\"4A级景区\", \"历史古镇\", \"免费开放\", \"民俗文化\"]','ACTIVE','2025-10-16 10:43:00','2025-10-16 10:43:00',NULL),(5,NULL,0,'MHSD005','明湖国家湿地公园','六盘水','自然景观','4A','贵州省六盘水市钟山区明湖路','城市中的生态湿地，适合休闲观光，免费开放。','明湖国家湿地公园位于贵州省六盘水市钟山区，是国家4A级旅游景区，也是国家湿地公园。公园总面积303公顷，其中湿地面积125.38公顷，是六盘水市的\"城市之肺\"。\r\n\r\n     公园特色：\r\n     - 湿地生态：多种水生植物和鸟类栖息地\r\n     - 环湖步道：5公里环湖步道，适合散步、慢跑、骑行\r\n     - 观鸟平台：可观赏白鹭、野鸭等多种水鸟\r\n     - 荷花池：夏季荷花盛开，美不胜收\r\n\r\n     休闲设施：\r\n     - 亲水平台：可近距离接触湖水\r\n     - 儿童游乐区：适合亲子游玩\r\n     - 观景亭：多个观景点，可欣赏湖光山色\r\n     - 自行车道：可租赁自行车环湖骑行\r\n\r\n     游览建议：\r\n     - 免费开放，全天候开放\r\n     - 早晨和傍晚景色最美\r\n     - 适合亲子游、家庭游\r\n     - 可带野餐垫，在草坪上休闲',NULL,NULL,26.5848000,104.8442000,'全天开放','免费','2-3小时',4000,4.7,0,3789,0,'[\"4A级景区\", \"湿地公园\", \"免费开放\", \"城市休闲\"]','ACTIVE','2025-10-16 10:43:00','2025-10-16 10:43:00',NULL);
/*!40000 ALTER TABLE `scenic_spots` ENABLE KEYS */;
