INSERT INTO `site_configs` (`id`, `config_key`, `config_json`, `created_at`, `updated_at`) VALUES (1,'landing','{\"stats\":[{\"id\":1,\"label\":\"预测准确率\",\"target\":96,\"suffix\":\"%\"},{\"id\":2,\"label\":\"覆盖景区\",\"target\":5,\"suffix\":\"+\"},{\"id\":3,\"label\":\"平均响应\",\"target\":180,\"suffix\":\"ms\"}],\"features\":[{\"id\":1,\"icon\":\"🔮\",\"title\":\"智能客流预测\",\"description\":\"基于LSTM-ARIMA混合模型，精准预测景区未来客流趋势\"},{\"id\":2,\"icon\":\"🗺️\",\"title\":\"行程规划\",\"description\":\"AI算法优化游览路线，避开高峰节省时间\"},{\"id\":3,\"icon\":\"📊\",\"title\":\"实时数据分析\",\"description\":\"3D可视化大屏，实时监控景区运营状态\"}],\"highlights\":[{\"id\":1,\"badge\":\"地域适配\",\"title\":\"六盘水本地化\",\"desc\":\"结合地形气候/节假日/民族节庆等在地特征进行模型调优\",\"points\":[\"✓ 气候与季节特征工程\",\"✓ 景区承载与出入口流向\",\"✓ 本地交通/节庆事件注入\",\"测试\"]},{\"id\":2,\"badge\":\"AI 预测\",\"title\":\"混合时序算法\",\"desc\":\"LSTM × ARIMA 叠加假日增强，短中期客流趋势更稳\",\"points\":[\"✓ 96%+ 验证集准确率目标\",\"✓ 小样本场景鲁棒性优化\",\"✓ 预测区间与置信度输出\"]},{\"id\":3,\"badge\":\"3D 可视化\",\"title\":\"沉浸式数据大屏\",\"desc\":\"三维地图与实时指标联动，热点/拥挤区一目了然\",\"points\":[\"✓ 热点热力/人流轨迹联动\",\"✓ 阈值预警与消息推送\",\"✓ 多终端自适应展示\"]}],\"scenarios\":[{\"id\":1,\"icon\":\"🚦\",\"title\":\"高峰错峰与导流\",\"desc\":\"节假日提前预警并优化入园时段，减少拥堵\"},{\"id\":2,\"icon\":\"🚌\",\"title\":\"交通接驳编排\",\"desc\":\"预测客流峰谷，动态调整公交与摆渡车频次\"},{\"id\":3,\"icon\":\"🛡️\",\"title\":\"承载与安全保障\",\"desc\":\"超阈值实时告警，联动安保与广播提示\"}],\"testimonials\":[{\"content\":\"预测结果基本贴合实际，我们的游客投诉率明显下降。\",\"author\":\"水城古镇\",\"role\":\"运营经理\"},{\"content\":\"高峰时的接驳车辆调度效率提升了不少。\",\"author\":\"市文旅局\",\"role\":\"数据科\"},{\"content\":\"路线规划对避开排队很有帮助，游客体验更好了。\",\"author\":\"玉舍森林公园\",\"role\":\"游客服务\"}]}','2025-10-11 20:43:42','2026-02-22 02:01:48');
